        const currentUpgrade = getCurrentUpgrade(originalSubmission);
        const numberOfPages = (currentUpgrade?.actionPageIds || []).length;

        if (numberOfPages > 1) {
          const dismissedUpgrades = dismissUpgrade(request.actionPageId!);

          if (dismissedUpgrades.length < numberOfPages) {
            return;
          }
        }

        if (shouldActivateUpgrade && !isEvent) {
          activateNextUpgrade(originalSubmission);
