                (funds ?? [])
                  .filter((fund) => fund.shown || fund.shown === null)
                  .map((fund) => {
                    const { percentage, type: fundType } = fund;
                    const allocationAmount = Math.round(
                      ((percentage ?? 0 / 100) * ticketTotalAmountAfterDiscount) / 100
                    );

                    return {
                      actionPagesFundId: fund.fund.id,
                      amount: allocationAmount,
                      fundType: fundType === 'direct' ? null : fundType,
                    };
                  })
              : // Add ticket total after discount proportionally to amountAllocations
                (amountAllocationsAttributes ?? []).map((allocation) => {
